import socket
import json
import time
import random

# Server configuration
HOST = '0.0.0.0'  # Listen on all available network interfaces
PORT = 27015      # A common port for game server status (e.g., Quake 3, CS 1.6)

# --- Mock Game State Data ---
# This dictionary holds the current state of the game server.
# Some fields (like uptime, current_players, players list) will be updated dynamically.
initial_game_state = {
    "server_name": "Awesome Python Game Server #1",
    "map": "Forest_Arena_v3",
    "game_mode": "Team Deathmatch",
    "current_players": 0,  # Will be updated dynamically
    "max_players": 24,
    "version": "1.0.0-beta",
    "password_protected": False,
    "uptime_seconds": 0,   # Will be updated dynamically
    "players": []          # Will be updated dynamically
}

start_time = time.time()

# --- Helper Functions for Mock Data ---
def generate_mock_players(num_players, max_players):
    """Generates a list of mock player dictionaries."""
    players = []
    player_names_pool = [
        "ShadowHunter", "ViperStrike", "PhoenixRising", "GhostBlade", "Specter",
        "WarlockKing", "RogueAgent", "BlazeRunner", "FuryFlame", "StormBreaker",
        "ThunderBolt", "EchoWarrior", "FrostGiant", "IronHide", "Nightmare",
        "ZeusPrime", "ApolloWing", "HadesGate", "ThorSmash", "LokiTrickster"
    ]
    random.shuffle(player_names_pool) # Shuffle to get varied names

    for i in range(min(num_players, max_players)):
        player = {
            "name": player_names_pool[i % len(player_names_pool)],
            "score": random.randint(0, 250),
            "kills": random.randint(0, 100),
            "deaths": random.randint(0, 50),
            "ping": random.randint(20, 180),
            "team": "Red" if i % 2 == 0 else "Blue" if i % 3 == 0 else "Green" # Simulate multiple teams
        }
        players.append(player)
    return players

def update_game_state(current_state_dict):
    """
    Updates the dynamic fields of the game state dictionary.
    This simulates changes in a real game server.
    """
    current_state_dict["uptime_seconds"] = int(time.time() - start_time)

    # Simulate players joining and leaving
    # Randomly set number of current players, up to max_players
    num_mock_players = random.randint(0, current_state_dict["max_players"])
    current_state_dict["players"] = generate_mock_players(num_mock_players, current_state_dict["max_players"])
    current_state_dict["current_players"] = len(current_state_dict["players"])

    # Simulate map changes occasionally
    if random.random() < 0.05: # 5% chance to change map on an update
        maps = ["Desert_Canyon_v2", "Urban_Ruins_night", "Arctic_Outpost", "Volcanic_Pits"]
        current_state_dict["map"] = random.choice(maps)

    return current_state_dict

# --- UDP Game Server Logic ---
def run_udp_server():
    """
    Starts and runs the UDP server to respond to status queries.
    """
    # Create a UDP socket
    sock = socket.socket(socket.AF_INET, socket.SOCK_DGRAM)

    try:
        # Bind the socket to the host and port
        sock.bind((HOST, PORT))
        print(f"UDP game status server listening on {HOST}:{PORT}")
        print("Waiting for status queries (send 'GET_STATUS')...")

        while True:
            # Receive data and the address of the sender
            # 4096 bytes is a generous buffer for a UDP request,
            # but actual requests are typically small (e.g., "GET_STATUS")
            data, addr = sock.recvfrom(4096)
            request_message = data.decode('utf-8').strip()

            print(f"\nReceived '{request_message}' from {addr}")

            if request_message == "GET_STATUS":
                # Create a copy of the initial state to modify dynamically
                # This prevents modifying the global 'initial_game_state' directly
                current_game_state = initial_game_state.copy()
                # Update the dynamic parts of the game state
                updated_state = update_game_state(current_game_state)

                # Serialize the updated game state to a JSON string
                # We do not use indent for a compact response, saving bandwidth.
                response_json = json.dumps(updated_state)
                response_bytes = response_json.encode('utf-8')

                # Send the response back to the client
                sock.sendto(response_bytes, addr)
                print(f"Sent status response ({len(response_bytes)} bytes) to {addr}")
            else:
                print(f"Ignoring unknown request: '{request_message}'")

    except KeyboardInterrupt:
        print("\nServer is shutting down...")
    except Exception as e:
        print(f"An unexpected error occurred: {e}")
    finally:
        sock.close()
        print("Server socket closed.")

if __name__ == "__main__":
    run_udp_server()